exports.seed = async function (knex) {
  console.log('\n_ Seed 70: Sinkronisasi Judul & Frekuensi dari XLSX Resmi...\n');

  let updated = 0;
  let skipped = 0;
  const errors = [];

  for (const upd of ITEM_UPDATES) {
    try {
      const rows = await knex('monitoring_items')
        .where('item_code', upd.kode)
        .update({
          title: upd.title,
          duty_cluster: upd.duty_cluster,
          frequency_type: upd.frequency_type,
        });
      if (rows > 0) updated++;
      else skipped++;
    } catch (err) {
      errors.push(upd.kode + ': ' + err.message);
    }
  }

  console.log('   Total item diproses : ' + ITEM_UPDATES.length);
  console.log('   Updated             : ' + updated + ' item');
  console.log('   Skipped (not found) : ' + skipped + ' item');
  if (errors.length > 0) {
    console.log('   Errors              : ' + errors.length);
    errors.slice(0, 5).forEach(function(e) { console.log('      - ' + e); });
  }

  // Verifikasi sample
  const samples = await knex('monitoring_items')
    .whereIn('item_code', ['AMP-001','AMP-010','PZ-001','AKIP-001','REG-001'])
    .select('item_code', 'title', 'duty_cluster', 'frequency_type');

  console.log('\n   Verifikasi sample:');
  samples.forEach(function(s) {
    console.log('    [' + s.item_code + '] ' + s.title.substring(0,80));
    console.log('           Rumpun: ' + s.duty_cluster + ' | Freq: ' + s.frequency_type);
  });

  console.log('\n Seed 70 selesai - ' + updated + ' judul item telah disinkronisasi!\n');
};